INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (1.5, 1, 122601, "仲間と夏を楽しむ、夏海の魔法士。自分を変えたいという固い決意で、障害物を無効化して走り続ける。", 101, 160, 0.029, 105, 0, 0, 110, 1, 1, 1);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (2.5, 0, 122401, "太陽よりも輝く、夏海の元気娘。　持ち前の身体能力で、どんなコースも柔軟に対応し、駆け抜ける。", 102, 120, 0.014, 111, 1, 0, 105, 3, 2, 2);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (2.5, 0, 122501, "波打ち際に煌めく、夏海の剣士。　日々の鍛錬で鍛えた脚で、長い距離も速度を落とさず走り切る。", 103, 350, 0.017, 105, 0, 1, 110, 2, 3, 3);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (1.5, 0, 107501, "海の幸に目がない、渚のお姫様。　『王家の装備』の力を解放し、障害物をものともせず前へと進む。", 104, 130, 0.016, 105, 1, 0, 110, 3, 4, 4);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (2.5, 1, 107601, "海でも主さまをお世話する、白浜の巫女。精霊の力で自身を加速させ、誰よりも速くゴールを目指す。", 105, 160, 0.014, 105, 0, 0, 110, 1, 5, 5);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (3.5, 0, 107801, "水着姿を恥じらう、ツンデレ猫娘。お得意の魔法で、対戦相手の走りを妨害し、レースを有利に進める。", 106, 255, 0.029, 103, 0, 1, 120, 2, 6, 6);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (3.5, 1, 110601, "優雅に浜を駆ける、真夏のマホ姫。しゃなりしゃなりと、雅な身のこなしで障害物を跳び越えていく。", 107, 160, 0.013, 103, 0, 0, 120, 1, 7, 7);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (2.5, 0, 110401, "浜の平和を守る、真夏の狼娘。　　獣人の強靭なスタミナで、レース　後半にスパートをかける。", 108, 350, 0.014, 103, 0, 1, 110, 2, 8, 8);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (1.5, 0, 110501, "浜に力強く舞う、真夏の南国娘。　レースの喧噪の中でも精神を乱さず後半に大きな捲りを見せる。", 109, 130, 0.012, 100, 1, 0, 105, 3, 9, 9);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (2.5, 1, 115701, "浜の事件を嗅ぎ付けた、真夏の　　名探偵。高い推理力と魔法で、的確に対戦相手の走りを乱す。", 110, 200, 0.014, 103, 0, 0, 105, 1, 10, 10);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (2.5, 0, 113601, "再び鎧を脱いだ、灼熱の騎士団長。実戦で培った判断力で、瞬時にバリアを展開し、障害物を無力化する。", 111, 350, 0.071, 103, 0, 1, 105, 2, 11, 11);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (1.5, 0, 107901, "水が苦手な、海辺の気まぐれ猫娘。浜に現れた美少女義賊は、対戦相手のスピードを奪いとる。", 112, 130, 0.014, 103, 1, 0, 120, 3, 12, 12);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (1.5, 1, 108001, "バカンスも効率第一な、海の傭兵。レースでも最高効率を求め、どんな状況でも隙のない走りを見せる。", 113, 200, 0.022, 105, 0, 0, 110, 2, 13, 13);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (2.5, 1, 110301, "真夏の太陽が良く似合う、海辺の　サレンママ。多才で器用、どんな　障害物もエレガントに越えていく。", 114, 160, 0.031, 108, 0, 0, 110, 1, 14, 14);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (0.5, 0, 107701, "海に嵐を呼ぶ夏のドジっ娘メイド。日頃から災難に慣れており、多少　のトラブルには動じたりしない。", 115, 130, 0.036, 105, 1, 0, 110, 1, 15, 15);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (3.5, 0, 113101, "粋な夏を愉しむ、若夏の姉御。　　流麗な身体捌きで、始・継・終と、UBを重ねるごとに、加速する。", 116, 350, 0.048, 95, 0, 1, 110, 2, 16, 16);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (1.5, 0, 113301, "夏のトキメキに触れた、オタク魔法少女。多彩な魔法を操り、少しずつ他の走者の速度を落とし続ける。", 117, 130, 0.043, 105, 1, 0, 105, 3, 17, 17);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (1.5, 0, 113201, "海獄に降臨せし、真夏の冥姫。　　レース後半に魔力を全解放し、　　蒼き疾風と成りて浜を駆け抜ける。", 118, 130, 0.018, 95, 1, 0, 105, 2, 18, 18);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (2.5, 1, 117001, "夏の夕を火花で彩る、渚の壊し屋。『壊し屋』の異名と過激な愛情は、対戦相手にプレッシャーを与える。", 119, 160, 0.021, 108, 0, 0, 110, 2, 19, 19);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (2.5, 0, 113501, "青春に生きる者を導く、夏の先生。夢へと邁進する聖母の加護が、その身をあらゆる困難から守る。", 120, 255, 0.036, 105, 0, 1, 110, 1, 20, 20);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (2.5, 0, 113401, "笑顔の応援が眩しい、夏の超能力　ガール。超能力を駆使して、どんな障害物もひとっ飛びで乗り越える。", 121, 350, 0.02, 105, 0, 1, 105, 3, 21, 21);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (2.5, 0, 110101, "海辺で大人の魅力を放つ、夏の　　セクシー先生。その魅力に囚われた対戦相手は、走りを乱してしまう。", 122, 130, 0.018, 105, 1, 0, 110, 1, 22, 22);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (3.5, 1, 110001, "水着も絶対外さない、夏のカリスマモデル。走りのバイブスは超テンアゲで、スピードはおにやば。", 123, 160, 0.03, 111, 0, 0, 105, 3, 23, 23);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (1.5, 0, 117201, "南の島も盛り上げる、真夏のアイドル。悪天候でも笑顔を絶やさず後半もリズムを上げて走り切る。", 124, 130, 0.027, 103, 1, 0, 110, 1, 24, 24);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (3.5, 1, 117301, "海原に美声を響かす、渚の歌姫。　守護の賛歌と精霊の加護により、　障害物から身を守る。", 125, 160, 0.02, 108, 0, 0, 105, 2, 25, 25);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (2.5, 0, 117401, "夏でも天邪鬼な、夕凪のテーラー。張り巡らされた魔法の糸で、他の走者の自由を奪う。", 126, 350, 0.04, 105, 0, 1, 110, 3, 26, 26);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (3.5, 0, 117101, "向日葵が良く似合う、海辺の　　　お姉ちゃん。秘密結社の一員で、　抜群の身体能力が一番の武器。", 127, 350, 0.009, 105, 0, 1, 110, 1, 27, 27);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (3.5, 0, 122901, "渚でおっとり、夏色うさぎっこ。　うさぎさんパワー全開で、ぴょん　ぴょんとコースを跳ね回る。", 128, 255, 0.022, 105, 0, 1, 120, 1, 28, 28);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (2.5, 0, 122801, "無邪気さ弾ける、夏色いたずら娘。砂浜でも、いたずらの準備は万端！レースに大波乱が巻き起こる！？", 129, 130, 0.028, 105, 1, 0, 110, 3, 29, 29);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (3.5, 1, 122701, "海でも真面目な、夏色優等生。　　高めた魔力を解き放ち、一瞬の内に他の走者を置き去りにする。", 130, 130, 0.023, 108, 0, 0, 105, 2, 30, 30);
